# 获取服务器PID
$proc = Get-NetTCPConnection -LocalPort 10280 -ErrorAction SilentlyContinue | Where-Object { $_.State -eq 'Listen' } | Select-Object -First 1
if ($proc) {
    Write-Output "Stopping PID $($proc.OwningProcess)..."
    Stop-Process -Id $proc.OwningProcess -Force
    Start-Sleep -Seconds 2
}

# 重新启动
Set-Location "D:\astro_py\astro_hub"
Start-Process -FilePath "python" -ArgumentList "start.py" -WindowStyle Hidden
Start-Sleep -Seconds 5

# 验证
try {
    $resp = Invoke-WebRequest -Uri "http://localhost:10280" -UseBasicParsing -TimeoutSec 5
    Write-Output "Server OK: $($resp.StatusCode)"
} catch {
    Write-Output "Server check: $_"
}
